<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import { Edit3, Plus, RefreshCw, Save, Search, Trash2, X } from '@lucide/vue'
import { useI18n } from 'vue-i18n'
import { createOperatorResource, deleteOperatorResource, listOperatorResource, updateOperatorResource, type OperatorResource } from '@/api/operator'

export interface CrudField { key:string; label:string; type?:'text'|'number'|'textarea'|'select'|'email'|'datetime-local'; options?:Array<{value:string;label:string}>; required?:boolean; min?:number; step?:number; default?:unknown }
export interface CrudColumn { key:string; label:string; format?:'money'|'status'|'number' }
type Entity = Record<string, any> & {id:string}
const props=defineProps<{resource:OperatorResource;title:string;subtitle:string;createLabel:string;fields:CrudField[];columns:CrudColumn[]}>()
const {t}=useI18n();const loading=ref(false);const saving=ref(false);const error=ref('');const message=ref('');const query=ref('');const items=ref<Entity[]>([]);const modalOpen=ref(false);const editing=ref<Entity|null>(null);const form=reactive<Record<string,any>>({})
const filtered=computed(()=>{const keyword=query.value.trim().toLowerCase();return items.value.filter(item=>!keyword||props.columns.some(column=>String(item[column.key]??'').toLowerCase().includes(keyword)))})
function reset(){for(const field of props.fields)form[field.key]=field.default??(field.type==='number'?0:'')}
function openCreate(){editing.value=null;reset();modalOpen.value=true}
function openEdit(item:Entity){editing.value=item;for(const field of props.fields)form[field.key]=item[field.key]??field.default??'';modalOpen.value=true}
function close(){modalOpen.value=false;editing.value=null}
function display(value:any,format?:string){if(format==='money')return new Intl.NumberFormat(undefined,{style:'currency',currency:'USD',maximumFractionDigits:6}).format(Number(value||0)/1_000_000);if(format==='number')return new Intl.NumberFormat().format(Number(value||0));return value||'-'}
async function load(){loading.value=true;error.value='';try{items.value=await listOperatorResource(props.resource) as Entity[]}catch(err){error.value=err instanceof Error?err.message:t('common.failed')}finally{loading.value=false}}
async function save(){saving.value=true;error.value='';try{if(editing.value)await updateOperatorResource(props.resource,editing.value.id,{...form});else await createOperatorResource(props.resource,{...form});message.value=t('common.saved');close();await load()}catch(err){error.value=err instanceof Error?err.message:t('common.failed')}finally{saving.value=false}}
async function remove(item:Entity){if(!window.confirm(t('operatorCrud.deleteConfirm')))return;try{await deleteOperatorResource(props.resource,item.id);await load()}catch(err){error.value=err instanceof Error?err.message:t('common.failed')}}
onMounted(load)
</script>
<template><main class="content crud-page"><section class="page-header"><div><h1>{{title}}</h1><p>{{subtitle}}</p></div><button class="button" type="button" @click="openCreate"><Plus :size="17"/>{{createLabel}}</button></section><div class="crud-summary"><span><strong>{{items.length}}</strong>{{t('operatorCrud.records')}}</span><span><strong>{{items.filter(item=>item.status==='active'||item.status==='published').length}}</strong>{{t('dashboard.active')}}</span></div><section class="table-toolbar"><label class="search-box"><Search :size="17"/><input v-model="query" :placeholder="t('operatorCrud.search')"/></label><button class="button secondary" type="button" :disabled="loading" @click="load"><RefreshCw :size="17"/>{{t('common.refresh')}}</button></section><div v-if="message" class="notice success">{{message}}</div><div v-if="error" class="notice">{{error}}</div><section class="panel table-panel"><div class="panel-body table-scroll"><table class="data-table crud-table"><thead><tr><th v-for="column in columns" :key="column.key">{{column.label}}</th><th>{{t('common.actions')}}</th></tr></thead><tbody><tr v-for="item in filtered" :key="item.id"><td v-for="column in columns" :key="column.key"><span v-if="column.format==='status'" class="pill" :class="item[column.key]==='active'||item[column.key]==='published'?'status-success':'status-warning'">{{item[column.key]}}</span><template v-else>{{display(item[column.key],column.format)}}</template></td><td class="table-actions"><button class="icon-button" type="button" :title="t('common.edit')" @click="openEdit(item)"><Edit3 :size="16"/></button><button class="icon-button danger" type="button" :title="t('operatorCrud.delete')" @click="remove(item)"><Trash2 :size="16"/></button></td></tr><tr v-if="!filtered.length"><td :colspan="columns.length+1" class="empty-cell"></td></tr></tbody></table></div></section><div v-if="modalOpen" class="modal-backdrop" @click.self="close"><form class="modal-card" @submit.prevent="save"><header class="modal-header"><div><h2>{{editing?t('common.edit'):createLabel}}</h2><p>{{subtitle}}</p></div><button class="icon-button" type="button" @click="close"><X :size="18"/></button></header><div class="modal-body form-grid"><div v-for="field in fields" :key="field.key" class="field" :class="{'field-wide':field.type==='textarea'}"><label>{{field.label}}</label><textarea v-if="field.type==='textarea'" v-model="form[field.key]" rows="3" :required="field.required"/><select v-else-if="field.type==='select'" v-model="form[field.key]" :required="field.required"><option v-for="option in field.options" :key="option.value" :value="option.value">{{option.label}}</option></select><input v-else v-model="form[field.key]" :type="field.type||'text'" :required="field.required" :min="field.min" :step="field.step"/></div></div><footer class="modal-footer"><button class="button secondary" type="button" @click="close">{{t('common.cancel')}}</button><button class="button" type="submit" :disabled="saving"><Save :size="17"/>{{saving?t('common.saving'):t('common.save')}}</button></footer></form></div></main></template>
